VALUES
  ('pukao-0c700c30-moex-00264', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '假設一消費者之效用函數為U(X,Y)=aX+bY(a>0且b>0)，兩財貨的價格分別為P =1與P =2，若其效 X Y 用極大化時，消費者將所得全用於購買X，請問參數a與b應滿足下列那個條件？', '["2a>b", "2a<b", "a>2b", "a<2b"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00265', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '假設一消費者僅消費兩種財貨，且兩財貨價格相等，請問在效用極大的唯一內部解上，下列何種條件必須 成立？', '["兩財貨支出相等", "兩財貨邊際效用相等", "兩財貨需求彈性相等", "兩財貨消費者剩餘相等"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00266', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '若某廠商的唯一投入要素是勞動，且總生產函數上存在一反曲點，關於該廠商邊際生產力、平均生產力與 此反曲點，下列敘述何者正確？', '["反曲點的左側對應的勞動邊際生產力遞減", "反曲點的左側對應的勞動平均生產力遞減", "反曲點的右側對應的勞動平均生產力遞減", "反曲點的右側對應的勞動邊際生產力遞減"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00267', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '獨占市場的需求曲線為Q = 20 − P，其中P為價格，Q是數量。此獨占廠商所面對的邊際收益曲線（MR） 為何？', '["MR=20", "MR = 10 − Q", "MR = 20 −Q", "MR = 20 − 2Q"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00268', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '獨占廠商利潤極大化的一階條件為何？', '["邊際收益等於邊際成本", "平均收益等於平均成本", "價格等於邊際成本", "價格等於平均成本"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00269', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '在短期的完全競爭市場當中，假設勞工是可變動的要素投入。有關個別廠商供給曲線移動，下列敘述何 者正確？', '["勞工的工資上升時，個別廠商的供給曲線會往右邊移動", "勞工的工資上升時，個別廠商的供給曲線會往左邊移動", "勞工的工資上升時，個別廠商的供給曲線移動方向不確定", "勞工的工資上升時，個別廠商的供給曲線不會移動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00270', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '既然自由貿易對兩國皆有利，為何還有部分團體強力反對？', '["自由貿易長期受益，但短期會受害，故有反對聲浪", "自由貿易兩國受益程度不一，受益少的國家有理由反對", "自由貿易生產者受益，但消費者受害，因而反對", "自由貿易對兩個國家總體都有利，但部分產業與廠商受害，造成部分員工失業，這些人會反對"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00271', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '如果所得收入保持不變並且工資率增加，那麼工作時間將會：', '["增加", "減少", "保持不變", "不能確定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00272', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '在一完全競爭市場中，供給線為正斜率，需求線為負斜率，且廠商的生產造成外部成本。在沒有管制的情 況下，該市場的均衡價格與銷售量分別為P1與Q1，而社會最適的價格與銷售量分別為P2與Q2。下列敘 述何者正確？', '["P1>P2，Q1>Q2", "P1>P2，Q1<Q2", "P1<P2，Q1>Q2", "P1<P2，Q1<Q2"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00273', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '在一完全競爭市場，其需求函數為P=100 Q，供給函數為P=10，此處P為價格（單位為元），Q為數 量。假設所有廠商均為同質，且廠商每生產一單位產品所造成的邊際外部成本為2元。下列何者為社會最 − 適的生產量？', '["88", "89", "90", "92"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL)
